-- Import data alamat dari src/data/generated/alamat.json
-- Bagian 1 dari 20. Jalankan setelah sql/create_alamat_riwayat_tables.sql.
-- Aman dijalankan berulang.
SET NAMES utf8mb4;
USE `si_data`;

ON DUPLICATE KEY UPDATE
  `id_pegawai` = VALUES(`id_pegawai`),
  `tipe` = VALUES(`tipe`),
  `jalan` = VALUES(`jalan`),
  `kelurahan` = VALUES(`kelurahan`),
  `kecamatan` = VALUES(`kecamatan`),
  `kota_kabupaten` = VALUES(`kota_kabupaten`),
  `provinsi` = VALUES(`provinsi`),
  `kode_provinsi` = VALUES(`kode_provinsi`),
  `kode_kota_kab` = VALUES(`kode_kota_kab`),
  `kode_kecamatan` = VALUES(`kode_kecamatan`),
  `kode_kelurahan` = VALUES(`kode_kelurahan`),
  `created_at` = VALUES(`created_at`);
